// Instancias a monitorear
const instances = [
  { name: 'GenerAriseV2', key: $env.EVOLUTION_KEY_GENERARISE || 'TU_KEY' },
  { name: 'Argenterio', key: $env.EVOLUTION_KEY_ARGENTERIO || 'TU_KEY' },
  { name: 'durando',    key: $env.EVOLUTION_KEY_DURANDO    || 'TU_KEY' },
];

const EVOLUTION_URL = 'https://trafic.generarise.space';
const results = [];

for (const inst of instances) {
  try {
    const res = await fetch(`${EVOLUTION_URL}/instance/connectionState/${inst.name}`, {
      headers: { 'apikey': inst.key }
    });
    const data = await res.json();
    const state = data?.instance?.state || 'unknown';
    results.push({
      name: inst.name,
      state: state,
      ok: state === 'open',
      emoji: state === 'open' ? '✅' : '🔴'
    });
  } catch(e) {
    results.push({
      name: inst.name,
      state: 'ERROR: ' + e.message,
      ok: false,
      emoji: '❌'
    });
  }
}

const allOk = results.every(r => r.ok);
const statusLines = results.map(r => `${r.emoji} *${r.name}*: ${r.state}`).join('\n');
const timestamp = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

return [{
  json: {
    allOk,
    results,
    statusLines,
    timestamp,
    mensaje: allOk
      ? `✅ *Sistema Neurova OK*\n${statusLines}\n\n_${timestamp}_`
      : `🚨 *ALERTA — Instancia Caída*\n\n${statusLines}\n\n⚡ Entrá a: https://trafic.generarise.space/manager/ para reconectar\n\n_${timestamp}_`
  }
}];

// Solo loguear que todo está OK (no manda mensaje para no spamear)
console.log('✅ Todas las instancias OK —', new Date().toISOString());
return [{ json: { status: 'ok' } }];
